            Refresh();
        })
        .catch((err)=>console.log(err))
    }
    return(
        <div className="container-fluid" id="to-do-list">
            <Table striped bordered hover>
                <thead>
                    <tr>
                        <th>ID</th>
                        <th>Description</th>
                        <th>Priority</th>
                        <th>Status</th>
                        <th>Target Date</th>
                        <th>UserID</th>
                    </tr>
                </thead>
                <tbody>
                    {
                        tasks.map((task)=>{
                            return(<tr>
                                <td>{task.id}</td>
                                <td>{task.description}</td>
                                <td>{task.priority}</td>
                                <td>{task.status}</td>
                                <td>{task.target_date}</td>
                                <td>{task.user_id}</td>
                                <td>
                                    <Button variant="outline-info" size="sm" onClick={()=> setModalEditOpen(true)}>Edit</Button>
                                    {isModalEditOpen && <EditTask id={task.id} open={isModalEditOpen} onCloseEditng={()=>setModalEditOpen(false)}/>}
                                </td>
                                <td><Button variant="outline-danger" size="sm">Delete</Button></td>
                            </tr>
                            )
                        })
                    }
                </tbody>
            </Table>
        </div>
    )
}

export default TodoList;
